// tests/e2e/fixtures/auth-setup.ts
import { test as setup } from '@playwright/test';

setup('authenticate', async ({ page }) => {
  await page.goto('/login');
  await page.getByLabel('Email').fill(process.env.TEST_USER_EMAIL!);
  await page.getByLabel('Password').fill(process.env.TEST_USER_PASSWORD!);
  await page.getByRole('button', { name: 'Sign in' }).click();
  await page.waitForURL('/dashboard');
  await page.context().storageState({ path: 'playwright/.auth/user.json' });
});

test('shows payment error on gateway failure', async ({ page }) => {
  await page.route('**/api/payments', route =>
    route.fulfill({ status: 503, body: JSON.stringify({ error: 'gateway unavailable' }) })
  );
  await page.goto('/checkout');
  await page.getByRole('button', { name: 'Pay now' }).click();
  await expect(page.getByText('Payment service unavailable')).toBeVisible();
});

import { faker } from '@faker-js/faker';

export function createUserData(overrides: Partial<User> = {}): User {
  return {
    email: faker.internet.email(),
    name: faker.person.fullName(),
    role: 'user',
    ...overrides,
  };
}

